import java.util.Scanner;

public class BufferOverflowExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine(); // Use nextLine() instead of next()

        // Limit the input size to 10 characters
        String truncatedName = name.substring(0, Math.min(name.length(), 10));

        char[] buffer = new char[10];

        // Copy truncated user input into the buffer
        truncatedName.getChars(0, truncatedName.length(), buffer, 0);

        System.out.println("Hello, " + new String(buffer));
    }
}

